  ('disabled-c5fb3965-moex-00273', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-3082b5f1', 'sub-disabled-c5fb3965-08', NULL, 'single_choice', '關於最高行政法院大法庭裁定之拘束力，下列敘述何者正確？', '["有拘束全國各機關及人民之效力", "有拘束各級行政法院之效力", "對提案庭提交之事件有拘束力", "有拘束所有行政機關之效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00274', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-3082b5f1', 'sub-disabled-c5fb3965-08', NULL, 'single_choice', '有關行政法上「不當聯結禁止」原則之敘述，下列何者錯誤？', '["不當聯結禁止原則，不可將不相干之要素納入考慮", "此一原則為行政法上之基本原則", "不當聯結禁止原則，與「恣意禁止」精神同其旨趣", "行政機關對人民課以一定義務時，其所採之手段與目的間，縱未必有合 理之聯結關係，亦受容許"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00275', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-3082b5f1', 'sub-disabled-c5fb3965-08', NULL, 'single_choice', '下列何者非屬私經濟行政？', '["市民購買悠遊卡搭乘公車或捷運", "衛生福利部中央健康保險署與醫院診所簽訂醫事服務合約", "主管機關與人民訂立社會住宅租賃契約", "財政部出售台灣高鐵持股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
