  ('disabled-c5fb3965-moex-00280', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-111-3082b5f1', 'sub-disabled-c5fb3965-08', NULL, 'single_choice', '公務人員保障法對於公務人員之權益救濟採行復審制與申訴制，下列敘述 何者錯誤？', '["復審係向公務人員保障暨培訓委員會提出", "申訴係向原處分機關為之", "公務員對於復審決定不服者，不得對之提起行政訴訟", "申訴係行政機關內部管理措施之自我檢討審查程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
